#!/usr/bin/env node
// Workaround for KERN-GAP: @kernlang/fastapi 3.5.0 emits a TS-style
// `// @generated by kern …` header into `.py` files, which Python rejects
// (`//` is floor division, not a comment). Rewrite the header to `#`.
// Delete this script once @kernlang/fastapi emits Python-style headers.

import { readdirSync, readFileSync, statSync, writeFileSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const root = join(dirname(fileURLToPath(import.meta.url)), '..', 'src', 'generated');

function walk(dir) {
  for (const entry of readdirSync(dir)) {
    const full = join(dir, entry);
    const st = statSync(full);
    if (st.isDirectory()) walk(full);
    else if (st.isFile() && full.endsWith('.py')) fixHeader(full);
  }
}

function fixHeader(path) {
  const text = readFileSync(path, 'utf8');
  const lines = text.split('\n');
  if (lines[0]?.startsWith('// ')) {
    lines[0] = '# ' + lines[0].slice(3);
    writeFileSync(path, lines.join('\n'));
    console.log(`  fix-python-header: rewrote header in ${path.replace(root, 'src/generated')}`);
  }
}

walk(root);
